import { Type } from '@nestjs/common';
import { isFunction, isString } from '@nestjs/common/utils/shared.utils';
import 'reflect-metadata';
import { DECORATORS } from '../constants';
import { createApiPropertyDecorator } from '../decorators/api-property.decorator';
import { METADATA_FACTORY_NAME } from '../plugin/plugin-constants';

export class ModelPropertiesAccessor {
  getModelProperties(prototype: Type<unknown>): string[] {
    const properties =
      Reflect.getMetadata(DECORATORS.API_MODEL_PROPERTIES_ARRAY, prototype) ||
      [];

    return properties
      .filter(isString)
      .filter(
        (key: string) => key.charAt(0) === ':' && !isFunction(prototype[key])
      )
      .map((key: string) => key.slice(1));
  }

  applyMetadataFactory(prototype: Type<unknown>) {
    const classPrototype = prototype;
    do {
      if (!prototype.constructor) {
        return;
      }
      if (!prototype.constructor[METADATA_FACTORY_NAME]) {
        continue;
      }
      const metadata = prototype.constructor[METADATA_FACTORY_NAME]();
      const properties = Object.keys(metadata);
      properties.forEach((key) => {
        createApiPropertyDecorator(metadata[key], false)(classPrototype, key);
      });
    } while (
      (prototype = Reflect.getPrototypeOf(prototype) as Type<any>) &&
      prototype !== Object.prototype &&
      prototype
    );
  }
}

import { Type } from '@nestjs/common';
import { DECORATORS } from '../constants';
import { getSchemaPath } from '../utils';
import { CallBackObject } from '../interfaces/callback-object.interface';

export const exploreApiCallbacksMetadata = (
  instance: object,
  prototype: Type<unknown>,
  method: object
) => {
  const callbacksData = Reflect.getMetadata(DECORATORS.API_CALLBACKS, method);
  if (!callbacksData) return callbacksData;

  return callbacksData.reduce(
    (acc, callbackData: CallBackObject<string | Function>) => {
      const {
        name: eventName,
        callbackUrl,
        method: callbackMethod,
        requestBody,
        expectedResponse
      } = callbackData;
      return {
        ...acc,
        [eventName]: {
          [callbackUrl]: {
            [callbackMethod]: {
              requestBody: {
                required: true,
                content: {
                  'application/json': {
                    schema: {
                      $ref: getSchemaPath(requestBody.type)
                    }
                  }
                }
              },
              responses: {
                [expectedResponse.status]: {
                  description:
                    expectedResponse.description ||
                    'Your server returns this code if it accepts the callback'
                }
              }
            }
          }
        }
      };
    },
    {}
  );
};

